module top_module(
    input [47:0]mantise,
    input clk, clear, load,
    output reg [47:0]saved_mants
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    begin
        if(clear)
            saved_mants <= 48'b0;
        else if(load)
            saved_mants <= mantise;
    end

endmodule
